module binary_counter_8bit(
    input       clk    ,
    input       reset  ,
    input       enable ,

    output reg [7:0]  count
);

   // Binary Counter with enable and reset
     wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
       if (reset) begin
           count <= 8'b0;
       end else if (enable) begin
           count <= count + 1;
       end
   end

endmodule
